SELECT COUNT(*) AS total_price_records, AVG(price) AS average_price
FROM instrument_prices
WHERE instrument_id = 1;

SELECT COUNT(*) AS total_instruments
FROM portfolio_instruments
WHERE portfolio_id = 1;

SELECT DISTINCT p.portfolio_name
FROM portfolios p
INNER JOIN portfolio_instruments pi ON p.portfolio_id = pi.portfolio_id;

SELECT SUM(portfolio_value) AS total_portfolio_value
FROM portfolio_values
WHERE valuation_date = (SELECT MAX(valuation_date) FROM portfolio_values);

SELECT sector_id, COUNT(*) AS instrument_count
FROM instrument_sectors
GROUP BY sector_id;

SELECT clients.client_name, portfolios.portfolio_name
FROM clients
JOIN portfolios ON clients.client_id = portfolios.client_id;
